getgenv().SCRIPT_KEY = "KEYLESS"

local INV_URL = "https://t.me/tsumfreescripts"

local function openInvestigationLink()
    pcall(function()
        game:GetService("GuiService"):OpenBrowserWindow(INV_URL)
    end)
    pcall(function()
        if syn and syn.open_url then syn.open_url(INV_URL) end
    end)
    pcall(function()
        if fluxus and fluxus.open_in_browser then fluxus.open_in_browser(INV_URL) end
    end)
    if setclipboard then
        setclipboard(INV_URL)
    end
end

local Rayfield = loadstring(game:HttpGet('https://sirius.menu/rayfield'))()
local Junkie = loadstring(game:HttpGet("https://jnkie.com/sdk/library.lua"))()

Junkie.service = "tSUM"
Junkie.identifier = "1082994"
Junkie.provider = "PulseHub"

-- отключаем проверку ключа Junkie (локально)
Junkie.check_key = function(_key)
    return { valid = true, message = "KEY_VALID" }
end

-- перехват HTTP к Junkie API (если Luraph проверяет ключ снова)
do
    local req = (syn and syn.request) or (http and http.request) or request or http_request
    if req then
        local function patchedRequest(opts)
            if type(opts) == "table" and type(opts.Url) == "string" and string.find(opts.Url, "jnkie.com", 1, true) then
                return { StatusCode = 200, Body = '{"valid":true,"message":"KEY_VALID"}' }
            end
            return req(opts)
        end
        request = patchedRequest
        http_request = patchedRequest
        if syn then syn.request = patchedRequest end
        if http then http.request = patchedRequest end
    end
end

local enteredCode = ""
local canProceed = false

local AuthWindow = Rayfield:CreateWindow({
    Name = "Pulsenation tsum",
    LoadingTitle = "Pulsenation tsum",
    LoadingSubtitle = "расследование by t.me/tsumfreescripts",
    ConfigurationSaving = { Enabled = false },
    Discord = { Enabled = false, Invite = "" },
    KeySystem = false,
})

local AuthTab = AuthWindow:CreateTab("Вход", 4483362458)
AuthTab:CreateSection("расследование by t.me/tsumfreescripts")

AuthTab:CreateInput({
    Name = "Введите 1 для продолжения",
    PlaceholderText = "1",
    RemoveTextAfterFocusLost = false,
    Callback = function(Text)
        enteredCode = Text
    end,
})

AuthTab:CreateButton({
    Name = "Открыть t.me/tsumfreescripts",
    Callback = function()
        openInvestigationLink()
        Rayfield:Notify({
            Title = "Расследование",
            Content = "Ссылка открыта или скопирована: t.me/tsumfreescripts",
            Duration = 4,
            Image = 4483362458,
        })
    end,
})

AuthTab:CreateButton({
    Name = "Продолжить",
    Callback = function()
        if enteredCode == "1" then
            getgenv().SCRIPT_KEY = "KEYLESS"
            canProceed = true
            Rayfield:Notify({
                Title = "Готово",
                Content = "Загрузка скрипта...",
                Duration = 2,
                Image = 4483362458,
            })
            task.wait(0.5)
            AuthWindow:Destroy()
        else
            Rayfield:Notify({
                Title = "Подсказка",
                Content = 'Введите "1" в поле выше и нажмите снова.',
                Duration = 4,
                Image = 4483362458,
            })
        end
    end,
})

while not canProceed do
    task.wait(0.1)
end

getgenv().SCRIPT_KEY = "KEYLESS"

